var kthDistinct = function(arr, k) {
    const counts = new Map();
    for (const x of arr) counts.set(x, (counts.get(x) || 0) + 1);
    const distinct = arr.filter(x => counts.get(x) === 1);
    return k <= distinct.length ? distinct[k - 1] : '';
};
